mapper.select:
SELECT p.*, u.real_name as ownerName, o.building as ownerBuilding, o.unit as ownerUnit, o.room_number as ownerRoomNumber FROM payment p LEFT JOIN owner o ON p.owner_id = o.id LEFT JOIN sys_user u ON o.user_id = u.id
AND p.owner_id = #{ownerId}
AND p.status = #{status}
AND p.period = #{period}
ORDER BY p.create_time DESC
